// Auto-generated from https://taiko.wiki/diffchart/clear/10
// Maps "songNo:difficulty" -> tier name for ★10 clear difficulty chart

export const TIER_ORDER: readonly string[] = ["SSS","SS","S+","S","A","B","C","D","E","F","X"] as const

/** Higher index = easier/lower tier. Returns -1 if not on chart. */
export function tierRank(tier: string): number {
  return TIER_ORDER.indexOf(tier)
}

// Auto-generated from https://taiko.wiki/diffchart/dfc/10
// Maps "songNo:difficulty" -> tier name for ★10 DFC difficulty chart
// Sub-tiers (직력/개인차) are merged into a single tier label per level.

export const DFC_TIER_ORDER: readonly string[] = ["SS","S+","S","A+","A","B","C","D","E","F"] as const

/** Higher index = easier/lower tier. Returns -1 if not on chart. */
export function dfcTierRank(tier: string): number {
  return DFC_TIER_ORDER.indexOf(tier)
}

